fun solve(value: Array<Long>, limit: Array<Long>): Long {
    // Sort the elements based on their value in descending order
    val elements = value.mapIndexed({ i, v -> Pair(v, limit[i], i) } ).sortedWith(compareBy({ it.first }, { it.second }))

    val n = value.size
    val activated = BooleanArray(n)
    var total = 0L
    var activeCount = 0

    for (i in 0 until n) {
        // Check if the current element can be activated
        if (activeCount < elements[i].second) {
            // Activate the element
            activated[elements[i].third] = true
            total += elements[i].first
            activeCount++
        }
    }

    return total
}
